"use strict";(self.webpackChunkclassroom_scrapper_site=self.webpackChunkclassroom_scrapper_site||[]).push([[4551],{1975(a){a.exports=JSON.parse('{"tag":{"label":"probability","permalink":"/classroom-scrapper/tags/probability","allTagsPath":"/classroom-scrapper/tags","count":10,"items":[{"id":"ES 114 Probability, Statistics and Data Visualisation/Probability Theory/Lec_03_Axioms of Probability and Fundamental Properties","title":"Axioms of Probability and Their Corollaries","description":"Introduction to Probability Theory","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Probability Theory/Lec_03_Axioms of Probability and Fundamental Properties"},{"id":"ES119/Module 3/Lec_02_Bayesian Networks and Naive Bayes Classifier","title":"Bayesian Networks and Naive Bayes Classifier","description":"Recap: The Diagnostic Query","permalink":"/classroom-scrapper/ES119/Module 3/Lec_02_Bayesian Networks and Naive Bayes Classifier"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Probability Theory/Lec_04_Conditional Probability Definition and Axioms","title":"Conditional Probability Definition and Axioms","description":"This lecture formalizes the concept of conditional probability, a cornerstone of probabilistic reasoning. We will define it, differentiate it from joint probability, visualize it, and verify that it adheres to the fundamental axioms of probability theory.","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Probability Theory/Lec_04_Conditional Probability Definition and Axioms"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_12_Expectation of Continuous Random Variables","title":"Expectation of Continuous Random Variables","description":"In previous lectures, we established the framework for continuous random variables and their Probability Density Functions (PDFs). Today, we delve into one of the most fundamental concepts in probability theory: Expectation, which represents the average or mean value of a random variable.","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_12_Expectation of Continuous Random Variables"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_10_Expectation of Random Variables","title":"Expectation of Random Variables","description":"The concept of expectation is fundamental in probability theory, representing the \\"average\\" value of a random variable. It\'s not just a simple average but a weighted average, where each possible value of the random variable is weighted by its probability.","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_10_Expectation of Random Variables"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Probability Theory/Lec_05_Independence of Events","title":"Independence","description":"Introduction to Event Independence","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Probability Theory/Lec_05_Independence of Events"},{"id":"ES119/Module 3/Lec_01_Probabilistic Reasoning The Deterministic Baseline, Uncertainty, and Bayes\' Theorem","title":"Probabilistic Reasoning: Basics and Bayes\' Theorem","description":"1. The Deterministic Baseline & Its Limitations","permalink":"/classroom-scrapper/ES119/Module 3/Lec_01_Probabilistic Reasoning The Deterministic Baseline, Uncertainty, and Bayes\' Theorem"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_08_Probability Mass Functions","title":"Probability Mass Functions (PMF)","description":"---","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_08_Probability Mass Functions"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Probability Theory/Lec_02_Probability Space Fundamentals Sample Space, Events, and Probability Laws","title":"Probability Space","description":"Welcome to Lecture 2 of ES 114. Today, we embark on a journey into the fundamental building blocks of probability theory: the Probability Space. Understanding these core concepts is paramount for anyone delving into the fascinating world of uncertainty and random phenomena.","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Probability Theory/Lec_02_Probability Space Fundamentals Sample Space, Events, and Probability Laws"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_07_Introduction to Random Variables","title":"Random Variables Introduction","description":"In probability theory, experiments often yield outcomes that are descriptive rather than inherently numerical (e.g., \\"Head,\\" \\"Tail,\\" \\"rainy,\\" \\"sunny\\"). While these can be analyzed directly, mathematical operations like averaging or calculating variance become complex. Random variables serve as a crucial bridge, translating these descriptive outcomes into numerical values, thereby simplifying mathematical analysis.","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_07_Introduction to Random Variables"}],"unlisted":false}}')}}]);